const config = {
  toolRegistry: [
    {
      toolName: 'sprintHealthcheck',
      workflowId: 'KMrBMKLm9ZNezxwx',
      enabled: true,
      matchers: [
        { pattern: 'check\\s+sprint', flags: 'i' },
        {
          pattern: 'status\\s+sprint',
          flags: 'i',
          args: {
            additionalDestinations: [{ type: 'pushGoogleChat' }],
          },
        },
        { pattern: 'sprint\\s+status', flags: 'i' },
        { pattern: 'healthcheck', flags: 'i' },
      ],
    },
    {
      toolName: 'sprintRelease',
      workflowId: '__REGISTRY__:MoMo AI Assistant Tool Sprint Release',
      enabled: true,
      matchers: [
        {
          pattern: 'release\\s+sprint|close\\s+sprint|release\\s+status',
          flags: 'i',
          args: { commandType: 'release_sprint' },
        },
        {
          pattern: '(^|\\b)(approve|ok|dong y|đồng ý|xac nhan|xác nhận)(\\b|$)',
          flags: 'i',
          args: { commandType: 'approve' },
        },
        {
          pattern: '(^|\\b)(reject|tu choi|từ chối)(\\b|$)',
          flags: 'i',
          args: { commandType: 'reject' },
        },
        {
          pattern: '(^|\\b)(cancel|huy|hủy)(\\b|$)',
          flags: 'i',
          args: { commandType: 'cancel' },
        },
      ],
    },
    {
      toolName: 'demoCommand',
      workflowId: 'qbbI1Mu3JR3tPhZi',
      enabled: true,
      matchers: [
        {
          pattern: 'demo\\s+command|test\\s+demo',
          flags: 'i',
        },
      ],
    },
  ],
  fallbackAgent: {
    enabled: true,
    model: 'cx/gpt-5.4',
    defaultToolName: 'assistantGenericFallback',
    maxResultTextChars: 700,
    maxMessageTextChars: 3500,
    allowedDestinationTypes: ['reply', 'pushGoogleChat'],
    defaultDestinationsByChannel: {
      default: ['reply'],
      system: ['pushGoogleChat'],
    },
  },
};

return [
  {
    json: {
      ...$json,
      config,
    },
  },
];

const input = $('Config Main').first().json || {};
const config = input.config || {};
const toolRegistry = Array.isArray(config.toolRegistry) ? config.toolRegistry : [];
const commandText = String(input.commandText || '').trim();

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function toObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function mergeObjects(...objects) {
  return objects.reduce((acc, object) => ({ ...acc, ...toObject(object) }), {});
}

function buildRegex(matcher) {
  const pattern = toText(matcher?.pattern || '');
  if (!pattern) return null;

  try {
    return new RegExp(pattern, toText(matcher?.flags || 'i') || 'i');
  } catch (error) {
    return null;
  }
}

const incomingArgs = toObject(input.args);
let resolvedTool = null;

for (const tool of toolRegistry) {
  if (!tool || tool.enabled === false) continue;
  const matchers = Array.isArray(tool.matchers) ? tool.matchers : [];

  for (const matcher of matchers) {
    const regex = buildRegex(matcher);
    if (!regex || !regex.test(commandText)) continue;

    resolvedTool = {
      toolName: toText(tool.toolName),
      workflowId: toText(tool.workflowId),
      args: mergeObjects(incomingArgs, tool.args, matcher.args),
    };
    break;
  }

  if (resolvedTool) break;
}

const toolInput = {
  triggerSource: toText(input.triggerSource || 'chat'),
  commandText,
  channel: toText(input.channel || 'googleChat'),
  sessionId: toText(input.sessionId),
  spaceId: toText(input.spaceId),
  threadKey: toText(input.threadKey),
  actorId: toText(input.actorId),
  actorDisplayName: toText(input.actorDisplayName),
  args: toObject(resolvedTool?.args || incomingArgs),
};

const enabledTools = toolRegistry
  .filter((tool) => tool && tool.enabled !== false)
  .map((tool) => ({
    toolName: toText(tool.toolName),
    workflowId: toText(tool.workflowId),
    matcherPatterns: (Array.isArray(tool.matchers) ? tool.matchers : [])
      .map((matcher) => toText(matcher?.pattern))
      .filter(Boolean),
  }));

return [
  {
    json: {
      commandText,
      resolutionStatus: resolvedTool ? 'matched' : 'unsupported',
      resolvedTool,
      toolInput,
      args: toolInput.args,
      routerContext: {
        enabledTools,
        fallbackAgentEnabled: Boolean(config.fallbackAgent?.enabled),
      },
      fallbackAgent: toObject(config.fallbackAgent),
    },
  },
];

const resolved = $('Resolve Routed Tool').first().json || {};
const config = $('Config Main').first().json?.config || {};
const ai = $input.first()?.json || {};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function toObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function toArray(value) {
  return Array.isArray(value) ? value : [];
}

function unique(items) {
  return Array.from(new Set(items.filter(Boolean)));
}

function toPositiveNumber(value, fallback) {
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function truncate(value, maxChars) {
  const text = toText(value);
  if (!text || text.length <= maxChars) return text;
  return `${text.slice(0, Math.max(0, maxChars - 3)).trimEnd()}...`;
}

function normalizeLineBreaks(value) {
  const text = toText(value);
  if (!text) return '';

  if (text.includes('\\n') && !text.includes('\n')) {
    return text.replace(/\\n/g, '\n');
  }

  return text;
}

function extractJsonText(value) {
  const text = toText(value);
  if (!text) return '';

  const fencedMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fencedMatch?.[1]) return fencedMatch[1].trim();

  if (text.startsWith('{') || text.startsWith('[')) return text;

  const firstBraceIndex = text.indexOf('{');
  const lastBraceIndex = text.lastIndexOf('}');
  if (firstBraceIndex >= 0 && lastBraceIndex > firstBraceIndex) {
    return text.slice(firstBraceIndex, lastBraceIndex + 1).trim();
  }

  return '';
}

function tryParseJson(value) {
  const jsonText = extractJsonText(value);
  if (!jsonText || !jsonText.startsWith('{')) return null;

  try {
    return JSON.parse(jsonText);
  } catch (error) {
    return null;
  }
}

function normalizeStructuredCandidate(candidate) {
  if (!candidate) return null;
  if (typeof candidate === 'string') return tryParseJson(candidate);
  if (typeof candidate === 'object') return candidate;
  return null;
}

function normalizeDestinationTypes(rawDestinations, allowedTypes) {
  const requestedTypes = toArray(rawDestinations)
    .map((destination) => {
      if (typeof destination === 'string') return toText(destination);
      return toText(destination?.type || '');
    })
    .filter(Boolean);

  const filtered = requestedTypes.filter((type) => allowedTypes.includes(type));
  return unique(filtered);
}

function normalizeMessage(message, fallbackText, allowedTypes, maxMessageTextChars) {
  const messageObject = toObject(message);
  if (!Object.keys(messageObject).length) return null;

  const messageDestinations = normalizeDestinationTypes(messageObject.destinations, allowedTypes);
  const destinations = messageDestinations.length > 0 ? messageDestinations : allowedTypes;
  if (destinations.length === 0) return null;

  const rawPayload = toObject(messageObject.payload);
  const hasCardPayload = Array.isArray(rawPayload.cardsV2) && rawPayload.cardsV2.length > 0;
  const messageType = toText(messageObject.type || (hasCardPayload ? 'googleChatCardV2' : 'text')) || 'text';

  let payload = rawPayload;
  if (!Object.keys(payload).length) {
    const textFromMessage = truncate(normalizeLineBreaks(messageObject.text || fallbackText), maxMessageTextChars);
    if (!textFromMessage) return null;
    payload = { text: textFromMessage };
  }

  if (messageType === 'googleChatCardV2' && !Array.isArray(payload.cardsV2)) {
    const fallbackMessageText = truncate(normalizeLineBreaks(payload.text || fallbackText), maxMessageTextChars);
    if (!fallbackMessageText) return null;
    payload = { text: fallbackMessageText };
  }

  if (messageType === 'text') {
    const textPayload = truncate(normalizeLineBreaks(payload.text || fallbackText), maxMessageTextChars);
    if (!textPayload) return null;
    payload = { text: textPayload };
  }

  return {
    messageKey: toText(messageObject.messageKey || messageObject.key || 'fallbackReply') || 'fallbackReply',
    type: messageType,
    destinations,
    payload,
  };
}

const fallbackConfig = toObject(config.fallbackAgent);
const allowedSeeds = ['reply', 'pushGoogleChat'];
const configuredDestinationTypes = normalizeDestinationTypes(
  fallbackConfig.allowedDestinationTypes,
  allowedSeeds,
);
const allowedDestinationTypes = configuredDestinationTypes.length > 0
  ? configuredDestinationTypes
  : allowedSeeds;
const resultTextMaxChars = toPositiveNumber(fallbackConfig.maxResultTextChars, 700);
const messageTextMaxChars = toPositiveNumber(fallbackConfig.maxMessageTextChars, 3500);
const defaultToolName = toText(fallbackConfig.defaultToolName || 'assistantGenericFallback') || 'assistantGenericFallback';

const toolInput = toObject(resolved.toolInput);
const commandText = toText(toolInput.commandText || resolved.commandText || '');
const rawAiText = toText(ai.output ?? ai.response ?? ai.result ?? ai.text ?? ai.message?.content ?? '');

const structuredOutput = [
  ai,
  ai.output,
  ai.response,
  ai.result,
  ai.text,
  ai.message?.content,
]
  .map((candidate) => normalizeStructuredCandidate(candidate))
  .find((candidate) => candidate && typeof candidate === 'object') || {};

const fallbackResultText = commandText
  ? `Mình chưa map command "${commandText}" vào tool cố định nên đã xử lý bằng AI fallback.`
  : 'Mình chưa map command này vào tool cố định nên đã xử lý bằng AI fallback.';

const resultText = truncate(
  normalizeLineBreaks(toText(structuredOutput.resultText || structuredOutput.text || rawAiText) || fallbackResultText),
  resultTextMaxChars,
);

const defaultDestinationsByChannel = toObject(fallbackConfig.defaultDestinationsByChannel);
const channel = toText(toolInput.channel || 'googleChat');
const defaultTypesByChannel = channel === 'system'
  ? toArray(defaultDestinationsByChannel.system)
  : toArray(defaultDestinationsByChannel.default);
const defaultDestinationTypes = normalizeDestinationTypes(
  defaultTypesByChannel.length > 0 ? defaultTypesByChannel : ['reply'],
  allowedDestinationTypes,
);

const aiDeliveryPlan = toObject(structuredOutput.deliveryPlan);
const aiDestinationTypes = normalizeDestinationTypes(aiDeliveryPlan.destinations, allowedDestinationTypes);
const additionalDestinationTypes = normalizeDestinationTypes(
  toolInput.args?.additionalDestinations,
  allowedDestinationTypes,
);

let destinationTypes = unique([
  ...defaultDestinationTypes,
  ...aiDestinationTypes,
  ...additionalDestinationTypes,
]);

if (destinationTypes.length === 0) {
  destinationTypes = ['reply'];
}

const messages = toArray(aiDeliveryPlan.messages)
  .map((message) => normalizeMessage(message, resultText, destinationTypes, messageTextMaxChars))
  .filter(Boolean);

if (messages.length === 0) {
  messages.push({
    messageKey: 'fallbackReply',
    type: 'text',
    destinations: destinationTypes,
    payload: {
      text: truncate(resultText, messageTextMaxChars),
    },
  });
}

const inputThreadKey = toText(toolInput.threadKey);
const aiThreadKey = toText(aiDeliveryPlan.thread?.threadKey);
const commandSeed = (commandText || 'generic')
  .toLowerCase()
  .replace(/[^a-z0-9_-]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .slice(0, 40) || 'generic';
const generatedThreadKey = `assistant-fallback-${commandSeed}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
const threadKey = aiThreadKey || inputThreadKey || generatedThreadKey;

return [
  {
    json: {
      toolName: toText(structuredOutput.toolName || defaultToolName) || defaultToolName,
      resultText,
      deliveryPlan: {
        thread: {
          threadKey,
        },
        destinations: destinationTypes.map((type) => ({ type })),
        messages,
      },
      fallbackMeta: {
        resolutionStatus: toText(resolved.resolutionStatus || 'unsupported'),
        fallbackAgentEnabled: Boolean(fallbackConfig.enabled ?? true),
      },
    },
  },
];

